    //               "leverage":"0.00",
    //               "available_balance":"0.000000",
    //               "margin_usage":"0.00",
    //               "buying_power":"0"
    //            }
    //        },
    //        "timestamp": 1773158679717,
    //        "type": "update/user_stats"
    //    }
    //
    var channel any = this.SafeString(message, "channel", "")
